import xml.etree.ElementTree as ET
from typing import Union


def parse_xml_config(file_path: str) -> dict:
    """
    Parse an XML configuration file and return the settings as a dictionary.
    
    Handles nested elements, attributes, and repeated tags (as lists).
    
    Args:
        file_path: Path to the XML configuration file.
        
    Returns:
        A dictionary representing the XML configuration settings.
    """
    tree = ET.parse(file_path)
    root = tree.getroot()
    return {root.tag: _element_to_dict(root)}


def _element_to_dict(element: ET.Element) -> Union[dict, str]:
    """
    Recursively convert an XML element and its children into a dictionary.
    
    Args:
        element: An XML element to convert.
        
    Returns:
        A dictionary or string representation of the element.
    """
    result = {}

    # Add element attributes (prefixed with '@')
    if element.attrib:
        for key, value in element.attrib.items():
            result[f"@{key}"] = value

    # Process child elements
    children = list(element)
    if children:
        child_dict = {}
        for child in children:
            child_data = _element_to_dict(child)
            tag = child.tag

            if tag in child_dict:
                # Convert to list if there are multiple elements with the same tag
                existing = child_dict[tag]
                if not isinstance(existing, list):
                    child_dict[tag] = [existing]
                child_dict[tag].append(child_data)
            else:
                child_dict[tag] = child_data

        result.update(child_dict)
    else:
        # Leaf element: get the text content
        text = (element.text or "").strip()
        if result:
            # If there are attributes, store text under '#text' key
            if text:
                result["#text"] = text
        else:
            # No attributes, just return the text value
            return text

    return result


